        // create empty .env
        Files.createFile(tempDir.resolve(".env"));
        DotenvBuilder builder = Dotenv.configure().directory(tempDir.toString()).filename(".env");
        Dotenv dotenv = builder.load();
        Set<DotenvEntry> entries = dotenv.entries();
        assertTrue(entries.isEmpty(), "Expected no entries for empty .env");
        // verify no new system property
        assertNull(System.getProperty("ANY_KEY"), "No system properties should be set");
